import java.io.*;
import java.util.*;

public class Main {
    static class Pair {
        int start;
        int idx;
        Pair(int s, int i) { start = s; idx = i; }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int tc = 0; tc < T; tc++) {
            int N = Integer.parseInt(br.readLine().trim());
            int[] start = new int[N];
            int[] end = new int[N];
            for (int i = 0; i < N; i++) {
                StringTokenizer st = new StringTokenizer(br.readLine());
                start[i] = Integer.parseInt(st.nextToken());
                end[i] = Integer.parseInt(st.nextToken());
            }
            Pair[] arr = new Pair[N];
            for (int i = 0; i < N; i++) arr[i] = new Pair(start[i], i);
            Arrays.sort(arr, Comparator.comparingInt(p -> p.start));
            int[] sortedStarts = new int[N];
            int[] sortedIdx = new int[N];
            for (int i = 0; i < N; i++) {
                sortedStarts[i] = arr[i].start;
                sortedIdx[i] = arr[i].idx;
            }
            for (int i = 0; i < N; i++) {
                int pos = lowerBound(sortedStarts, end[i]);
                if (pos == N) out.append(-1);
                else out.append(sortedIdx[pos]);
                if (i + 1 < N) out.append(' ');
            }
            if (tc + 1 < T) out.append('\n');
        }
        System.out.print(out.toString());
    }
    private static int lowerBound(int[] arr, int target) {
        int l = 0, r = arr.length; // [l, r)
        while (l < r) {
            int m = (l + r) >>> 1;
            if (arr[m] >= target) r = m; else l = m + 1;
        }
        return l;
    }
}

